    //删除节点
    public void delLinkedList(int id)&#123;
        HeroNode temp = head; //辅助
        boolean flag = false;
        //找到待删除节点的前一个节点
        while (true)&#123;
            if(temp.next==null)&#123;
                break; //已经到最后需要退出循环
            &#125;
            if(temp.next.id ==id)&#123;
                flag = true;
                break;
            &#125;
            temp = temp.next;
            if(flag)&#123;
                //中间刚好空开一个.next
                temp.next = temp.next.next;
            &#125;else&#123;
                System.out.println("没有找到id为"+id);
            &#125;
        &#125;
